"""Check for errors in VictoriaLogs over the last hour."""

import httpx
import json
from datetime import datetime, timedelta

VICTORIALOGS_URL = "http://localhost:42010"

def check_errors():
    """Query VictoriaLogs for errors in the last hour."""
    try:
        # Query for ERROR severity logs
        query = "severity:ERROR"
        url = f"{VICTORIALOGS_URL}/select/logsql/query"
        params = {"query": query, "limit": 50}

        with httpx.Client() as client:
            resp = client.get(url, params=params, timeout=30.0)
            resp.raise_for_status()

            lines = resp.text.strip().split("\n")
            errors = []
            for line in lines:
                if line.strip():
                    try:
                        errors.append(json.loads(line))
                    except json.JSONDecodeError:
                        errors.append({"raw": line})

            if not errors:
                print("✅ No errors found in the logs.")
                return

            print(f"⚠️ Found {len(errors)} error(s) in the logs:\n")
            for i, err in enumerate(errors[:10], 1):
                timestamp = err.get("_time", err.get("timestamp", "unknown"))
                service = err.get("service.name", err.get("service", "unknown"))
                msg = err.get("msg", err.get("message", err.get("raw", "no message")))
                print(f"{i}. [{timestamp}] {service}: {msg[:200]}")
                if len(errors) > 10:
                    print(f"\n... and {len(errors) - 10} more errors")

    except httpx.ConnectError as e:
        print(f"❌ Could not connect to VictoriaLogs: {e}")
        print("   Make sure the VictoriaLogs container is running and accessible on port 42010")
    except httpx.HTTPError as e:
        print(f"❌ HTTP error: {e}")
    except Exception as e:
        print(f"❌ Error: {e}")

if __name__ == "__main__":
    check_errors()
