            lines = resp.text.strip().split("\n")
            errors = []
            for line in lines:
                if line.strip():
                    try:
                        errors.append(json.loads(line))
                    except json.JSONDecodeError:
                        errors.append({"raw": line})

            if not errors:
                print("No errors found.")
                return

